/**
 * IntegrationMarqueeSection - Animated integration logos showcase
 * Author: generated by Amazon Q
 * Created: 2025-01-20
 */

'use client';

import React, { useEffect, useRef, useState } from 'react';
import type { SectionConfig } from '@/lib/page-builder/section-schemas';

interface IntegrationApp {
  name: string;
  status: string;
  statusColor: 'green' | 'amber' | 'gray';
  iconType: 'emoji' | 'fontawesome' | 'fa' | 'svg' | 'image';
  icon?: string;
  iconConfig?: {
    type: 'fa';
    value: string;
    style: 'solid' | 'regular' | 'light' | 'thin' | 'duotone' | 'brands';
  };
  faIcon?: string;
  svgCode?: string;
  imageUrl?: string;
  bgColor?: string;
  iconColor?: string;
}

interface IntegrationMarqueeSectionProps {
  section: SectionConfig;
}

const IntegrationMarqueeSection: React.FC<IntegrationMarqueeSectionProps> = ({
  section,
}) => {
  const { data, style } = section;
  const {
    label = 'Connected Systems',
    row1Apps = [],
    row2Apps = [],
    row3Apps = [],
    row1Speed = 50,
    row2Speed = 45,
    row3Speed = 55,
  } = data;

  const [key, setKey] = useState(0);

  const trackRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    setKey(prev => prev + 1);
  }, [row1Apps, row2Apps, row3Apps]);

  const setTrackRef = (index: number) => (el: HTMLDivElement | null) => {
    trackRefs.current[index] = el;
  };

  const renderIcon = (app: IntegrationApp) => {
    switch (app.iconType) {
      case 'fa':
      case 'fontawesome':
        if (app.iconConfig) {
          const iconName = app.iconConfig.value?.replace(/^fa-/, '') || '';
          const styleMap: Record<string, string> = { solid: 'fas', regular: 'far', light: 'fal', thin: 'fat', duotone: 'fad', brands: 'fab' };
          const prefix = styleMap[app.iconConfig.style] || 'fas';
          return (
            <i
              className={`${prefix} fa-${iconName}`}
              style={{ fontSize: '20px', color: app.iconColor || 'currentColor', fontStyle: 'normal' }}
            />
          );
        }
        return (
          <i
            className={app.faIcon}
            style={{ fontSize: '20px', color: app.iconColor || 'currentColor', fontStyle: 'normal' }}
          />
        );
      case 'svg':
        return (
          <div
            dangerouslySetInnerHTML={{ __html: app.svgCode || '' }}
            style={{ width: '24px', height: '24px' }}
          />
        );
      case 'image':
        return (
          <img
            src={app.imageUrl}
            alt={app.name}
            className="w-6 h-6 object-contain"
          />
        );
      case 'emoji':
      default:
        return <span style={{ fontSize: '20px' }}>{app.icon || '📦'}</span>;
    }
  };

  const renderStatusDot = (color: 'green' | 'amber' | 'gray') => {
    const colors = {
      green: 'bg-green-500',
      amber: 'bg-amber-500',
      gray: 'bg-gray-400 dark:bg-gray-600',
    };
    return (
      <div className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${colors[color]}`} />
    );
  };

  const renderRow = (
    apps: IntegrationApp[],
    direction: 'left' | 'right',
    speed: number,
    index: number
  ) => {
    if (!apps || apps.length === 0) return null;

    const duplicatedApps = [...apps, ...apps, ...apps];

    return (
      <div key={`${index}-${key}`} className="relative overflow-hidden h-[72px]">
        {/* Fade gradients */}
        <div className="absolute left-0 top-0 bottom-0 w-24 bg-gradient-to-r from-white dark:from-neutral-900 to-transparent z-10 pointer-events-none" />
        <div className="absolute right-0 top-0 bottom-0 w-24 bg-gradient-to-l from-white dark:from-neutral-900 to-transparent z-10 pointer-events-none" />

        {/* Track */}
        <div className="flex animate-marquee-container">
          <div
            className="flex items-center gap-7 h-full flex-shrink-0"
            style={{
              animation: `marquee-${direction} ${speed}s linear infinite`,
            }}
          >
            {duplicatedApps.map((app, idx) => (
            <div
              key={`${app.name}-${idx}`}
              className="inline-flex items-center gap-2.5 px-5 py-3.5 rounded-xl bg-white dark:bg-neutral-800 border border-gray-200 dark:border-neutral-700 hover:border-gray-300 dark:hover:border-neutral-600 hover:bg-gray-50 dark:hover:bg-neutral-750 transition-all duration-200 hover:-translate-y-0.5 hover:scale-[1.03] cursor-pointer flex-shrink-0 h-14 shadow-sm"
            >
              <div
                className="w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 overflow-hidden"
                style={{
                  background: app.bgColor || 'rgba(100, 116, 139, 0.1)',
                }}
              >
                {renderIcon(app)}
              </div>
              <div className="flex flex-col">
                <div className="text-sm font-medium text-gray-900 dark:text-white leading-none">
                  {app.name}
                </div>
                <div className="text-[10px] text-gray-500 dark:text-gray-400 mt-0.5 leading-none">
                  {app.status}
                </div>
              </div>
              {renderStatusDot(app.statusColor)}
            </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  return (
    <section
      className={`${style?.backgroundColor || 'bg-white dark:bg-neutral-900'} ${
        style?.padding || 'py-16'
      }`}
    >
      <style jsx>{`
        @keyframes marquee-right {
          0% {
            transform: translateX(0%);
          }
          100% {
            transform: translateX(calc(-100% / 3));
          }
        }
        @keyframes marquee-left {
          0% {
            transform: translateX(calc(-100% / 3));
          }
          100% {
            transform: translateX(0%);
          }
        }
      `}</style>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {label && (
          <p className="text-[11px] font-medium tracking-widest uppercase text-gray-500 dark:text-gray-400 text-center mb-6">
            {label}
          </p>
        )}

        <div className="flex flex-col gap-5">
          {renderRow(row1Apps, 'right', row1Speed, 0)}
          {renderRow(row2Apps, 'left', row2Speed, 1)}
          {renderRow(row3Apps, 'right', row3Speed, 2)}
        </div>
      </div>
    </section>
  );
};

export default IntegrationMarqueeSection;
